mapper.select:
SELECT A.USER_ID ,A.USER_PW ,A.USER_NAME ,A.REGION_ID ,C.AREA_NAME AS REGION_NAME ,B.AUTH_NAME ,A.USER_TEL ,A.AUTH_CODE ,A.FLAG_USE ,A.MEMO ,A.IN_TEL ,DATE_FORMAT(A.REG_DT, '%Y-%m-%d') AS REG_DT ,D.ST ,D.FN ,CASE WHEN D.DF1 = '접속중' THEN '접속중' ELSE '미접속' END AS CN_YN FROM SYS_USER A
LEFT JOIN SYS_AUTH B ON A.AUTH_CODE = B.AUTH_CODE
LEFT JOIN CODE_AREACODE C ON A.REGION_ID = C.AREA_CODE
LEFT JOIN (SELECT T1.* ,CASE WHEN df > 0 THEN '미접속' ELSE '접속중' END AS df1 FROM (SELECT USER_ID ,DATE_FORMAT(MAX(ST_TIME), '%Y-%m-%d %H:%i:%s') AS ST ,DATE_FORMAT(MAX(FN_TIME), '%Y-%m-%d %H:%i:%s') AS FN ,SIGN(ROUND( TIMESTAMPDIFF(SECOND, MAX(ST_TIME), MAX(FN_TIME) ) )) AS df FROM LOGIN_HISTORY WHERE ST_TIME > DATE_SUB(NOW(), INTERVAL 2 DAY) GROUP BY USER_ID ) T1) D ON A.USER_ID = D.USER_ID
WHERE 1=1
AND A.USER_ID=#{userId}
AND A.USER_NAME=#{userName}
AND A.REGION_ID=#{regionId}
AND A.AUTH_CODE NOT IN ('999')
AND A.AUTH_CODE=#{authCode}
AND A.USER_ID LIKE CONCAT('%', #{searchValue}, '%')
AND A.USER_NAME LIKE CONCAT('%', #{searchValue}, '%')
AND A.REG_DT BETWEEN #{sDate} AND #{eDate}
ORDER BY A.REG_DT DESC

mapper.update:
UPDATE SYS_USER
SET

		USER_PW=#{userPw},

	 USER_NAME    = #{userName}
	,REGION_ID    = #{regionId}
	,AUTH_CODE    = #{authCode}
	,USER_TEL     = #{userPhone}
	,MEMO     = #{memo}
WHERE USER_ID=#{userId}

mapper.delete:
DELETE FROM LOGIN_HISTORY
WHERE USER_ID = #{userId}
AND FN_TIME IS NULL
